import os

def update_latex_manuscript():
    file_path = r"reports\latex\main_manuscript.tex"
    with open(file_path, "r", encoding="utf-8", errors="replace") as f:
        content = f.read()

    # Extract Dataset section text
    dataset_marker = "\\section{Dataset and Problem Formulation}\\label{sec2}"
    related_marker = "\\section{Related Work}\\label{sec3}"
    feature_marker = "\\section{Physics-Informed Feature Engineering}\\label{sec4}"
    
    idx_ds = content.find(dataset_marker)
    idx_rw = content.find(related_marker)
    idx_fe = content.find(feature_marker)
    
    if idx_ds == -1 or idx_rw == -1 or idx_fe == -1:
        print("Error locating section markers.")
        return
        
    dataset_text = content[idx_ds + len(dataset_marker):idx_rw].strip()
    # Replace label sec2 with sec3 inside dataset_text if referenced
    
    new_related_work = r"""
\section{Related Work}\label{sec2}

\subsection{Traditional BMS and Electrochemical Degradation Models}\label{subsec:traditional_bms}
Electrochemical modeling of lithium-ion batteries has historically relied on physical representations of internal reaction kinetics, mass transport, and thermodynamics \cite{plett2004extended,hu2012comparative,doyle1993modeling}. The foundational pseudo-two-dimensional (P2D) porous electrode model established by Doyle, Fuller, and Newman \cite{doyle1993modeling} formulates partial differential equations (PDEs) governing solid-state diffusion and electrolyte concentration gradients across active electrode materials. While P2D models offer unmatched fidelity in tracking internal lithium-ion intercalation mechanisms, their computational complexity---requiring the simultaneous numerical solution of coupled nonlinear PDEs---renders them unsuitable for real-time onboard execution within vehicle Battery Management Systems (BMS) \cite{santhanagopalan2006online,vetter2005ageing}. Furthermore, internal physical parameters such as solid-phase diffusion coefficients, reaction rate constants, and initial active material volume fractions cannot be measured non-invasively during vehicular operation \cite{lucu2018critical}. Consequently, classical physical models struggle to dynamically adapt to cell-to-cell manufacturing variability and non-uniform thermal gradients experienced across commercial EV battery packs \cite{li2019datadriven}.

\subsection{Equivalent Circuit Models and Impedance Spectroscopy for Aging}\label{subsec:ecm_eis}
To bridge the gap between complex electrochemical theory and real-time controller feasibility, Equivalent Circuit Models (ECMs) approximate cell dynamics using lumped electrical elements such as open-circuit voltage sources, ohmic resistors, and parallel resistor-capacitor ($R$-$C$) branches \cite{ng2009enhanced,berecibar2016critical}. Researchers have extensively applied Extended Kalman Filtering (EKF), Unscented Kalman Filtering (UKF), and particle filtering to estimate State of Charge (SOC) and internal resistance variations in real time \cite{plett2004extended,richardson2017gaussian}. Plett \cite{plett2004extended} demonstrated the effectiveness of EKF algorithms for HEV battery packs by tracking slow parameter drifts over operating cycles. Concurrently, Electrochemical Impedance Spectroscopy (EIS) has emerged as a rigorous diagnostic tool for quantifying aging mechanisms \cite{keil2016calendar,galeotti2015performance}. By applying broad-frequency sinusoidal excitations, EIS isolates high-frequency ohmic resistance (associated with electrolyte conductivity and contact degradation) from mid-frequency charge transfer resistance (governed by Solid Electrolyte Interphase growth) and low-frequency Warburg impedance (lithium diffusion restrictions) \cite{stroe2016degradation,pastor2017comparison}. However, traditional EIS instrumentation requires bulky hardware oscillators and long measurement times during equilibrium rest periods, which restricts its application during active vehicular driving or high-rate fast charging \cite{greenbank2021automated}. Moreover, while ECM parameters accurately indicate State of Health (SOH), predicting long-term Remaining Useful Life (RUL) solely from localized transfer functions remains prone to compounding extrapolation errors \cite{chen2022prognostics}.

\subsection{Data-Driven Prognostics and Benchmark Aging Cohorts}\label{subsec:datadriven_cohorts}
The emergence of open-source battery degradation repositories has shifted battery health monitoring toward data-driven machine learning pipelines \cite{severson2019data,li2021data}. Early investigations utilized benchmark datasets from the NASA Ames Prognostics Data Repository \cite{saha2007battery} and the Center for Advanced Life Cycle Engineering (CALCE), employing Support Vector Regression (SVR), Relevance Vector Machines (RVM), and Gaussian Process Regression (GPR) to model capacity fade curves \cite{peng2019integrated,richardson2018gaussian}. However, these early datasets primarily featured low-current constant-temperature cycling on small sample sizes ($<10$ cells), limiting out-of-distribution generalizability \cite{hu2020battery}. A significant breakthrough occurred with the work of Severson et al. \cite{severson2019data}, who released an extensive empirical dataset comprising 124 commercial A123 LFP cells cycled under 72 diverse multi-step fast-charging protocols ($1\text{C}$ to $6\text{C}$). Utilizing feature engineering on discharge voltage variance during early cycles ($Q_{100} - Q_{10}$), Severson et al. demonstrated that linear elastic net regression could forecast end-of-life cycle life with an out-of-sample Root Mean Squared Error (RMSE) of 128 cycles. Building on this cohort, Attia et al. \cite{attia2020closed} applied Bayesian optimization combined with early-cycle prediction to accelerate closed-loop fast-charging protocol discovery. While these benchmark studies proved that early life cycling telemetry contains hidden prognostic signatures, their static single-point prediction framework---evaluating data exclusively at cycle 100---cannot update forecasts continuously as battery usage patterns evolve later in life \cite{severson2020prognostic}.

\subsection{Deep Learning Architectures vs. Lightweight Gradient Boosting}\label{subsec:dl_vs_gbt}
To capture complex, non-linear degradation dependencies across continuous operating trajectories, recent literature has gravitated toward deep neural architectures \cite{hong2020scalable,hong2020deep}. Long Short-Term Memory (LSTM) networks and Gated Recurrent Units (GRUs) have been widely deployed to capture sequential temporal dependencies in voltage and current streams \cite{zhang2018long,chen2022transformer}. Zhang et al. \cite{zhang2018long} developed an LSTM framework capable of tracking long-range capacity degradation without handcrafted features. Recently, attention-based Transformer models have further pushed predictive benchmarks by modeling global sequence interactions across thousands of cycles \cite{hannun2023deep,yao2021attention}. Despite their high accuracy on workstation GPUs, deep architectures present critical barriers to embedded automotive adoption \cite{baricelli2023embedded,ke2017lightgbm}. Recurrent and attention layers require heavy floating-point matrix multiplications that consume substantial execution budgets ($>40\text{ ms}$ per inference) and flash memory footprints ($>15\text{ MB}$) on automotive microcontrollers \cite{chen2016xgboost}. Furthermore, deep neural networks function as uninterpretable black boxes, making formal verification against ISO 26262 automotive functional safety standards highly problematic \cite{iso26262}. In contrast, gradient-boosted decision trees---specifically LightGBM \cite{ke2017lightgbm}---offer an optimal structural compromise for edge BMS hardware. By employing leaf-wise tree growth with histogram-based continuous feature quantization, LightGBM executes non-linear decision thresholds using simple integer comparisons, requiring less than $1\text{ ms}$ inference time and under $1\text{ MB}$ of memory storage \cite{baricelli2023lightweight}.

\subsection{Uncertainty Quantification and Conformal Prediction in Prognostics}\label{subsec:uq_conformal}
A fundamental deficiency in current data-driven battery prognostics is the lack of mathematically reliable uncertainty calibration \cite{berecibar2016online,angelopoulos2021gentle}. Point predictions of RUL fail to communicate confidence bounds to vehicle controllers during safety-critical aging regimes \cite{vovk2005algorithmic}. Classical probabilistic approaches, such as Gaussian Process Regression (GPR) \cite{richardson2018gaussian} and Bayesian Neural Networks (BNNs) \cite{peng2019integrated}, attempt to model predictive variance but rely on strict parametric assumptions---most notably, that regression residuals follow Gaussian distributions with homoscedastic noise. In empirical battery aging, capacity fade trajectories frequently exhibit highly skewed, non-Gaussian distributions, particularly as cells transition into rapid late-life capacity collapse \cite{shafer2008tutorial}. When distributional assumptions are violated, Bayesian credible intervals become severely miscalibrated, often underestimating risk \cite{barber2023predictive}. To overcome these limitations, recent theoretical developments in distribution-free uncertainty quantification have centered on Conformal Prediction \cite{angelopoulos2021gentle,romano2019conformalized}. Originally formulated by Vovk et al. \cite{vovk2005algorithmic} and popularized by Angelopoulos and Bates \cite{angelopoulos2021gentle}, split-conformal prediction constructs finite-sample prediction intervals guaranteed to achieve exact user-specified coverage probabilities (e.g., $90\%$) across arbitrary underlying data distributions, relying solely on the assumption of exchangeability \cite{papadopoulos2002inductive,angelopoulos2021uncertainty}. While conformal prediction has gained traction in computer vision and medical diagnostics, its integration into dynamic, rolling-window battery prognostics on embedded automotive hardware remains unexplored. This work directly addresses this research gap by unifying LightGBM tree inference with split-conformal safety brackets.
"""

    new_dataset_section = "\n\\section{Dataset and Problem Formulation}\\label{sec3}\n\n" + dataset_text + "\n\n"
    
    new_content = content[:idx_ds] + new_related_work + new_dataset_section + content[idx_fe:]
    
    with open(file_path, "w", encoding="utf-8") as f:
        f.write(new_content)
    print("Successfully updated main_manuscript.tex with expanded Related Work as Section II and Dataset as Section III.")

if __name__ == "__main__":
    update_latex_manuscript()
